import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import { Subject } from "rxjs";
import { permissionsLabels } from "src/app/shared/models/fmosNewRolePermissions";
import { AccClosureMaintenanceServiceService } from "src/app/shared/services/acc-closure-maintenance-service.service";
import { RoleService } from "src/app/shared/services/role.service";

@Component({
  selector: "npr-account-closure-maintenance-summary",
  templateUrl: "./account-closure-maintenance-summary.component.html",
  styleUrls: ["./account-closure-maintenance-summary.component.scss"],
})
export class AccountClosureMaintenanceSummaryComponent implements OnInit {
  respArray: any;
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  roleCodes = new permissionsLabels();
  constructor(
    private roleService: RoleService,
    private accClosureService: AccClosureMaintenanceServiceService,
    private router: Router
  ) {}

  ngOnInit(): void {
    setTimeout(() => {
      this.newRolePermissions();
    }, 2000);
    this.roleService.screenLabelList.subscribe(message => this.roleCodes = message);
    setTimeout(() => {
      console.log(this.roleCodes);
    }, 3000);
    this.dtOptions = {
      pagingType: "full_numbers",
      pageLength: 5,
      processing: true, 
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]]
    };
    this.getAccountClosureMaintenancesummary();
  }
  newRolePermissions()
  {

    this.roleService.fetchScreenPermissions('Charge Maintenance');
  }
  getAccountClosureMaintenancesummary() {
    this.accClosureService
      .gettingAccountClosureMaintenance()
      .subscribe((summaryResp) => {
        this.respArray = summaryResp;
        this.dtTrigger.next();
      });
  }
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }
  new() {
    localStorage.removeItem('idValue');
    this.accClosureService.setIndex({
      index: "",
    });
    this.router.navigateByUrl("/account-closure-maintenance");
  }
  edit(data) {
    this.accClosureService.setIndex({
      index: data.accountType,
    });
    localStorage.setItem('idValue',data.accountType);
    this.router.navigateByUrl("/account-closure-maintenance");
  }
}
